const raw = $input.first().json?.content || $input.first().json?.data || "";
const lines = String(raw).split("\n").filter(l => l.trim().length > 20).slice(0,20);
const CURRENCIES = ["EUR","USD","GBP","JPY","CHF"];
const news = lines.map(l => ({
  headline: l.trim().slice(0,120),
  impact:   l.toLowerCase().includes("high") ? "high" : l.toLowerCase().includes("medium") ? "medium" : "low",
  currency: CURRENCIES.find(c => l.includes(c)) || ""
}));
return [{ json: { news } }];

const raw = $input.first().json?.content || $input.first().json?.data || "";
const lines = String(raw).split("\n").filter(l => l.trim().length > 10).slice(0,15);
const CURRENCIES = ["EUR","USD","GBP","JPY","CHF"];
const calendar = lines.map(l => ({
  event:    l.trim().slice(0,100),
  currency: CURRENCIES.find(c => l.includes(c)) || "",
  impact:   l.toLowerCase().includes("high") ? "high" : l.toLowerCase().includes("medium") ? "medium" : "low",
  time: "", forecast: ""
}));
return [{ json: { calendar } }];

// Triggered by Merge News+Cal (after News+Calendar branches complete).
// GET Prices and GET Positions completed earlier (faster FastAPI calls).
const prices    = $('GET Prices').first().json;
const posData   = $('GET Positions').first().json;
const positions = (posData.open || []).concat(posData.pending || []);
const newsItems = $input.all()
  .filter(i => i.json.news)
  .map(i => i.json.news)
  .flat();
const calItems  = $input.all()
  .filter(i => i.json.calendar)
  .map(i => i.json.calendar)
  .flat();
return [{ json: { prices, positions, news: newsItems, calendar: calItems } }];

